module RefModule(
    input clk,
    input rst,
    input [31:0] in,
    input in_valid,
    output reg [31:0] out,
    output reg out_valid
);reg [31:0] unused_sum;
reg [31:0] count;

always @(posedge clk) begin
    if (rst) begin
        unused_sum <= 0;
        count <= 0;
        out_valid <= 0;
    end else if (in_valid) begin
        unused_sum <= unused_sum + in;
        count <= count + 1;
    end else if (count > 0) begin
        out <= unused_sum;
        out_valid <= 1;
        unused_sum <= 0;
        count <= 0;
    end else begin
        out_valid <= 0;
    end
end

endmodule
